/**
 * Generate Antigravity rule metadata header
 * @param {object} frontmatter - Parsed frontmatter
 * @param {string} activation - Activation mode
 * @returns {string} - Formatted metadata
 */
export function generateAntigravityHeader(frontmatter: Record<string, unknown>, activation: string) {
  const { description } = frontmatter
  return `<!-- Antigravity Rule
Activation: ${activation}
// eslint-disable-next-line @typescript-eslint/no-base-to-string, @typescript-eslint/restrict-template-expressions, @typescript-eslint/prefer-nullish-coalescing
Description: ${description || "No description"}
-->\n\n`
}

/**
 * @param {Array<{ rel: string, content: string }>} items
 * @returns {Array<{ category: string, subgroups: Array<{ subcategory: string, rules: Array<{ rel: string, content: string }> }> }>}
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function groupByCategoryAndSubcategory(items: { rel: string; content: string; [key: string]: any }[]) {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const map: Record<string, Record<string, any[]>> = {}
  for (const item of items) {
    const parts = item.rel.split("/")
    const category = parts.length === 1 ? "root" : parts[0]
    const subcategory = parts.length >= 3 ? parts[1] : ""


    map[category!] = map[category!] ?? {}
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    map[category!]![subcategory!] = map[category!]![subcategory!] ?? []
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    map[category!]![subcategory!]!.push(item)
  }

  const categories = Object.keys(map).sort((a: string, b: string) => {
    if (a === "root") return -1
    if (b === "root") return 1
    return a.localeCompare(b)
  })
  return categories.map((category: string) => {
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    const subcatMap = map[category]!
    const subcategories = Object.keys(subcatMap).sort((a: string, b: string) => {
      // Keep empty subcategory first for readability (rules directly under category).
      if (a === "") return -1
      if (b === "") return 1
      return a.localeCompare(b)
    })

    const subgroups = subcategories.map((subcategory: string) => {
      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion, @typescript-eslint/no-explicit-any, @typescript-eslint/no-unsafe-return, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
      const rules = subcatMap[subcategory]!.slice().sort((a: any, b: any) => a.rel.localeCompare(b.rel))
      return { subcategory, rules }
    })

    return { category, subgroups }
  })
}

/**
 * Render a bundle of rules into a single markdown file (e.g. CLAUDE.md, AGENTS.md).
 *
 * @param {string} title - File title (e.g. "CLAUDE.md")
 * @param {Array<{ rel: string, content: string }>} bundle - Array of { rel, content }
 * @returns {string} - Rendered markdown
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function renderBundleMd(title: string, bundle: any[]) {
  const header = `# ${title}

This file is auto-generated by \`pnpm rules:compile\`.
Do not edit manually. Edit files in \`/rules\` and recompile.

## Project Rules

`
  const sections = bundle.map(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
    (item: any) => `## ${item.rel}

\`\`\`mdc
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access
${item.content}
\`\`\``,
  )
  return header + sections.join("\n\n") + "\n"
}

import path from "node:path"

/**
 * Render a bundle into a single markdown file with per-rule mdc blocks and frontmatter.
 * Used for GEMINI.md and WINDSURF.md.
 *
 * @param {string} title - File title (e.g. "GEMINI.md")
 * @param {string} subtitle - Section subtitle after "Project Rules" (e.g. "" or "(Windsurf/Cascade)")
 * @param {Array<{ rel: string, frontmatter: object, content: string }>} bundle - From generateBundle
 * @param {(item: { frontmatter: object }) => Record<string, string>} getExtraFrontmatter - Extra keys (e.g. activation, priority)
 * @returns {string} - Rendered markdown
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function renderBundleWithMdcFrontmatter(title: string, subtitle: string, bundle: any[], getExtraFrontmatter: (item: any) => any) {
  const header = `# ${title}

This file is auto-generated by \`pnpm rules:compile\`.
Do not edit manually. Edit files in \`/rules\` and recompile.

## Project Rules${subtitle ? ` ${subtitle}` : ""}

`
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const sections = bundle.map((item: any) => {
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const { rel, frontmatter, content } = item
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
    const normalizedRel = rel.split(path.sep).join("/")
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/prefer-nullish-coalescing
    const titleLine = frontmatter.description || rel
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const extra = getExtraFrontmatter(item)
    // eslint-disable-next-line @typescript-eslint/no-unsafe-argument
    const extraLines = Object.entries(extra)
      // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/restrict-template-expressions
      .map(([k, v]: [string, any]) => `${k}: "${v}"`)
      .join("\n")

    // eslint-disable-next-line @typescript-eslint/restrict-template-expressions
    return `## ${normalizedRel}

\`\`\`mdc
---
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions
description: "${titleLine}"
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/prefer-nullish-coalescing
globs: "${frontmatter.globs || "*"}"
// eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-member-access, @typescript-eslint/prefer-nullish-coalescing
alwaysApply: ${frontmatter.alwaysApply || false}
${extraLines ? extraLines + "\n" : ""}---

// eslint-disable-next-line @typescript-eslint/restrict-template-expressions, @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
${content.trim()}
\`\`\`
`
  })
  return header + sections.join("\n")
}

